INSERT INTO concern_data (concern, primary_treatments, secondary_treatments, description) VALUES
  ('넓은모공', '{"포텐자","시크릿RF"}', '{"피코슈어 프락셀","스킨보톡스","쥬베룩","리쥬란"}', '모공은 피지, 탄력 저하, 흉터가 함께 원인인 경우가 많아 니들 RF 계열과 콜라겐 부스터를 함께 고려해요.'),
  ('여드름 흉터', '{"일반 프락셀","피코슈어 프락셀","포텐자"}', '{"쥬베룩","리쥬란","리쥬란 S","쥬브아셀 3%"}', '패인 흉터는 피부 재생과 콜라겐 생성을 유도하는 시술이 주로 활용돼요.'),
  ('화농성여드름', '{"LDM","카프리 레이저"}', '{"시너지 MPX","스킨보톡스"}', '염증이 심할 때는 강한 박피보다 진정, 염증 완화 방향이 우선될 수 있어요.'),
  ('색소침착', '{"피코슈어 토닝","피코플러스 토닝"}', '{"LDM","리쥬란","물광주사"}', '색소는 레이저 계열이 많이 활용되지만, 피부장벽이 약하면 진정/재생도 함께 고려해요.'),
  ('탄력저하', '{"써마지","울쎄라"}', '{"포텐자","리쥬란","엘라비에 리투오","인모드 FX"}', '탄력 저하는 피부층, 지방층, 처짐 정도에 따라 고주파, 초음파, ECM 부스터를 나누어 고려해요.'),
  ('건조함', '{"리쥬란","물광주사"}', '{"셀르디엠","LDM","리쥬란 HB"}', '속건조나 피부결 저하는 수분 보충, 장벽 회복, 재생 계열 관리가 중심이 돼요.'),
  ('잔주름', '{"스킨보톡스","리쥬란"}', '{"써마지","물광주사","쥬베룩"}', '얕은 잔주름은 근육 움직임, 피부결, 수분감, 탄력 저하를 함께 봐야 해요.'),
  ('피부처짐', '{"울쎄라","올타이트"}', '{"써마지","인모드 FX","쥬베룩 볼륨"}', '처짐은 피부 탄력뿐 아니라 지방량과 얼굴 구조에 따라 리프팅 또는 볼륨 보완을 고려해요.'),
  ('이중턱', '{"인모드 FX","온다리프팅"}', '{"울쎄라","올타이트"}', '이중턱은 지방, 부종, 탄력 저하가 섞여 있어 지방 감소와 타이트닝 계열을 함께 고려해요.'),
  ('칙칙함', '{"피코슈어 토닝","물광주사"}', '{"LDM","리쥬란","스킨보톡스"}', '칙칙함은 색소, 건조, 피부결 저하가 복합적으로 작용해 톤, 광, 결 개선 방향으로 접근해요.'),
  ('수염/얼굴 털', '{"젠틀맥스 프로","아포지플러스 제모"}', '{"엘리트 제모"}', '얼굴이나 턱 수염은 제모 레이저로 모낭을 약하게 만들어 털을 얇아지게 해요. 반복 시술이 필요해요.'),
  ('홍조/붉은기', '{"시너지 MPX","시너지 제네시스"}', '{"LDM","리쥬란","카프리 레이저"}', '홍조나 늘어난 혈관은 혈관레이저 계열이 활용되고, 자극을 줄이는 진정 관리도 함께 고려해요.'),
  ('볼/팔자 꺼짐', '{"쥬베룩 볼륨","스컬트라"}', '{"쥬브아셀 8%","울쎄라","올타이트"}', '볼이나 팔자 주변 꺼짐은 콜라겐 부스터와 ECM 계열로 자연스럽게 차오르도록 보완할 수 있어요.'),
  ('눈가 잔주름', '{"눈가 보톡스","리쥬란 I"}', '{"스킨보톡스","LDM"}', '눈가는 얇고 예민한 부위라 근육 움직임을 줄이는 보톡스와 재생 부스터를 함께 고려해요.'),
  ('이마 주름', '{"이마 보톡스"}', '{"스킨보톡스","리쥬란"}', '이마 가로주름은 근육 움직임을 줄이는 보톡스가 주로 활용되고, 잔주름 관리는 스킨부스터를 함께 고려해요.'),
  ('미간 주름', '{"미간 보톡스"}', '{"스킨보톡스"}', '찡그릴 때 생기는 미간 주름은 보톡스로 근육 움직임을 줄여 인상을 부드럽게 해요.'),
  ('사각턱/턱근육', '{"사각턱 보톡스"}', '{"인모드 FX","울쎄라"}', '씹는 근육이 발달해 턱이 각져 보일 때 보톡스로 근육 크기를 줄이고, 탄력은 리프팅 계열로 보완해요.'),
  ('목 주름/밴드', '{"목밴드 보톡스"}', '{"리쥬란","스킨보톡스"}', '목 세로로 도드라지는 근육 라인은 보톡스로 완화하고, 목 피부결은 스킨부스터로 함께 관리해요.'),
  ('눈썹 처짐', '{"브로우 리프트 보톡스"}', '{"울쎄라","올타이트"}', '눈썹 꼬리가 처져 보일 때 보톡스로 근육 균형을 조절해 눈매를 열어주는 방향으로 접근해요.'),
  ('콧등 주름', '{"바니라인 보톡스"}', '{"스킨보톡스"}', '웃거나 찡그릴 때 코 옆에 잡히는 주름은 보톡스로 근육 움직임을 완화해요.'),
  ('입가 세로주름', '{"입가 잔주름 보톡스","리쥬란"}', '{"스킨보톡스","물광주사"}', '입가 얕은 세로주름은 소량 보톡스와 수분/재생 부스터를 함께 고려해요.'),
  ('울퉁불퉁한 턱끝', '{"턱끝 보톡스"}', '{"스킨보톡스"}', '턱끝에 자갈처럼 울퉁불퉁한 주름이 있을 때 소량 보톡스로 매끈하게 보이도록 해요.');
